mapper.select:
SELECT a.id, a.user_id AS userId, u.nickname AS nickname, u.image_url AS imageUrl, a.title, a.content,
a.country_id AS countryId, cou.name AS countryName, cou.icon AS countryIcon, a.category_id AS categoryId, cat.name AS categoryName, cat.icon AS categoryIcon,
COALESCE(l.like_count, 0) AS likeCount, COALESCE(c.comment_count, 0) AS commentCount, COALESCE(f.favorite_count, 0) AS favoriteCount,
CASE WHEN ul.user_id IS NOT NULL THEN TRUE ELSE FALSE END AS liked, CASE WHEN uf.user_id IS NOT NULL THEN TRUE ELSE FALSE END AS favorited,
a.created_time AS createdTime
FROM _articles a
JOIN _user u ON u.id = a.user_id LEFT JOIN _categories cat ON cat.id = a.category_id LEFT JOIN _countries cou ON cou.id = a.country_id
LEFT JOIN ( SELECT article_id, COUNT(*) AS like_count FROM _article_likes GROUP BY article_id ) l ON l.article_id = a.id
LEFT JOIN ( SELECT article_id, COUNT(*) AS comment_count FROM _comments GROUP BY article_id ) c ON c.article_id = a.id
LEFT JOIN ( SELECT article_id, COUNT(*) AS favorite_count FROM _article_favorites GROUP BY article_id ) f ON f.article_id = a.id
LEFT JOIN _article_likes ul ON ul.article_id = a.id AND ul.user_id = #{userId}
LEFT JOIN _article_favorites uf ON uf.article_id = a.id AND uf.user_id = #{userId}
AND a.user_id = #{query.authorId}
AND ( a.title LIKE CONCAT('%', #{query.keyword}, '%') OR a.content LIKE CONCAT('%', #{query.keyword}, '%') )
AND a.category_id = #{query.categoryId}
AND a.country_id = #{query.countryId}
AND a.id < #{query.lastId}
ORDER BY a.id DESC LIMIT #{query.size}

SELECT COUNT(*)
FROM _articles a


        AND (
        a.title LIKE CONCAT('%', #{keyword}, '%')
        OR a.content LIKE CONCAT('%', #{keyword}, '%')
        )


        AND a.category_id = #{categoryId}


        AND a.country_id = #{countryId}

SELECT a.id, a.user_id AS userId, u.nickname AS nickname,u.image_url AS imageUrl, a.title, a.content, a.country_id AS countryId, cou.name AS countryName, cou.icon AS countryIcon, a.category_id AS categoryId, cat.name AS categoryName, cat.icon AS categoryIcon, COALESCE(l.like_count, 0) AS likeCount, COALESCE(c.comment_count, 0) AS commentCount, COALESCE(f.favorite_count, 0) AS favoriteCount, CASE WHEN ul.user_id IS NOT NULL THEN TRUE ELSE FALSE END AS liked, TRUE AS favorited, a.created_time AS createdTime FROM _article_favorites af JOIN _articles a ON af.article_id = a.id JOIN _user u ON u.id = a.user_id LEFT JOIN _categories cat ON cat.id = a.category_id LEFT JOIN _countries cou ON cou.id = a.country_id LEFT JOIN (SELECT article_id, COUNT(*) AS like_count FROM _article_likes GROUP BY article_id) l ON l.article_id = a.id LEFT JOIN (SELECT article_id, COUNT(*) AS comment_count FROM _comments GROUP BY article_id) c ON c.article_id = a.id LEFT JOIN (SELECT article_id, COUNT(*) AS favorite_count FROM _article_favorites GROUP BY article_id) f ON f.article_id = a.id LEFT JOIN _article_likes ul ON ul.article_id = a.id AND ul.user_id = #{userId} WHERE af.user_id = #{userId}
AND a.id < #{query.lastId}
ORDER BY af.created_time DESC LIMIT #{query.size}
